import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import Header from "../components/Header";
import AnimatedPageWrapper from "../components/AnimatedPageWrapper";
import ProfileForm from "../components/ProfileForm";
import Questionnaire from "../components/Questionnaire";
import Loader from "../components/Loader";
import AlertBox from "../components/AlertBox";
import { fetchQuestionnaire, runAssessment } from "../api/assessment.api";
import { buildPayload } from "../utils/payloadBuilder";

export default function AssessmentPage() {
  const [step, setStep] = useState("start");
  const [profileData, setProfileData] = useState(null);
  const [questions, setQuestions] = useState([]);
  const [loading, setLoading] = useState(false);
  const [darkMode, setDarkMode] = useState(true);
  const [alert, setAlert] = useState("");

  const navigate = useNavigate();

  /* 🌙 Dark mode */
  useEffect(() => {
    document.documentElement.classList.toggle("dark", darkMode);
  }, [darkMode]);

  /* STEP 1 */
  const handleProfileSubmit = async (profile) => {
    setLoading(true);
    setProfileData(profile);

    try {
      const res = await fetchQuestionnaire(profile.currentClass);
      setQuestions(res.data.questions);
      setStep("questions");
    } catch {
      setAlert("Failed to load questions. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  /* STEP 2 */
  const handleAssessmentSubmit = async (answers) => {
    setLoading(true);

    try {
      const payload = buildPayload({ profileData, answers });
      const res = await runAssessment(payload);

      navigate("/report", {
        state: { reportUrl: res.data.reportUrl },
      });
    } catch {
      setAlert("Assessment failed. Please retry.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-white font-sans text-slate-900 selection:bg-indigo-100 selection:text-indigo-700">
      <Header darkMode={darkMode} setDarkMode={setDarkMode} />

      <AlertBox message={alert} onClose={() => setAlert("")} />

      {loading && <Loader />}

      {step === "start" && (
        <div className="relative isolate overflow-hidden bg-slate-900 min-h-[calc(100vh-80px)]">
            {/* Background gradient effects */}
          <div className="absolute inset-0 -z-10 h-full w-full bg-[#0B1120]">
              <div className="absolute inset-0 bg-gradient-to-tr from-[#0B1120] via-[#1a2c55] to-[#0B1120] opacity-80"></div>
                <div className="absolute bottom-0 right-0 h-[500px] w-[500px] bg-indigo-600/20 blur-[100px] rounded-full mix-blend-screen"></div>
          </div>

          <div className="mx-auto max-w-7xl px-6 lg:px-8 py-16 sm:py-24 lg:py-32">
            <div className="max-w-4xl text-left">
              <div className="flex items-center gap-2 mb-6">
                  {/* <img src="/logo-icon-white.png" className="w-6 h-6 opacity-80" alt="" /> */}
                  <span className="text-indigo-400 font-bold tracking-widest text-xs uppercase">
                    Welcome to College Reviewz
                  </span>
              </div>

              <h1 className="text-4xl font-bold tracking-tight text-white sm:text-6xl mb-6">
                India’s Most Trusted College Reviews <br className="hidden lg:block"/> & Counselling Platform
              </h1>

              <p className="mt-6 text-lg leading-8 text-gray-300 max-w-2xl">
                Discover top colleges, real student reviews, placements, fees, rankings, and everything you need to make the right decision for your future — all in one platform.
              </p>

              {/* Features */}
              <div className="mt-10 grid grid-cols-1 md:grid-cols-3 gap-6 text-white max-w-4xl">
                  <div className="flex items-start gap-3">
                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-6 h-6 text-white shrink-0">
                        <path strokeLinecap="round" strokeLinejoin="round" d="M9 12.75 11.25 15 15 9.75M21 12a9 9 0 1 1-18 0 9 9 0 0 1 18 0Z" />
                      </svg>
                      <div>
                            <h3 className="font-semibold">10,000+ Verified Student Reviews</h3>
                      </div>
                  </div>
                    <div className="flex items-start gap-3">
                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-6 h-6 text-white shrink-0">
                        <path strokeLinecap="round" strokeLinejoin="round" d="M9 12.75 11.25 15 15 9.75M21 12a9 9 0 1 1-18 0 9 9 0 0 1 18 0Z" />
                      </svg>
                      <div>
                            <h3 className="font-semibold">AI-powered College Matching</h3>
                      </div>
                  </div>
                    <div className="flex items-start gap-3">
                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-6 h-6 text-white shrink-0">
                        <path strokeLinecap="round" strokeLinejoin="round" d="M9 12.75 11.25 15 15 9.75M21 12a9 9 0 1 1-18 0 9 9 0 0 1 18 0Z" />
                      </svg>
                      <div>
                            <h3 className="font-semibold">Neutral, Unbiased Expert Guidance</h3>
                      </div>
                  </div>
              </div>

              {/* Search Bar - Visual Only */}
              <div className="mt-10 relative max-w-xl">
                  <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                    {/* Search Icon */}
                  </div>
                  <input
                    type="text"
                    disabled
                    className="block w-full rounded-full border-0 py-4 pl-6 pr-14 text-gray-900 shadow-sm ring-1 ring-inset ring-gray-300 placeholder:text-gray-400 bg-white/10 backdrop-blur-md text-white placeholder:text-gray-200 focus:ring-2 focus:ring-inset focus:ring-indigo-600 sm:text-sm sm:leading-6"
                    placeholder="Search College, Course, Exams or 10,000+ Verified Reviews..."
                  />
                  <div className="absolute inset-y-1 right-1">
                      <div className="h-full aspect-square bg-indigo-600 rounded-full p-2.5 flex items-center justify-center">
                            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-5 h-5 text-white">
                            <path strokeLinecap="round" strokeLinejoin="round" d="m21 21-5.197-5.197m0 0A7.5 7.5 0 1 0 5.196 5.196a7.5 7.5 0 0 0 10.607 10.607Z" />
                          </svg>
                      </div>
                  </div>
              </div>
              <p className="mt-2 text-xs text-gray-400">Every review is manually verified for authenticity.</p>


              {/* Buttons Action Area */}
              <div className="mt-10 flex flex-wrap gap-4">
                    <button
                      onClick={() => setStep("profile")}
                      className="rounded-full bg-white px-8 py-3.5 text-base font-bold text-indigo-900 shadow-sm hover:bg-gray-100 focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-white transition flex items-center gap-2"
                    >
                      Start Assessment & Earn Rewards
                      <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-5 h-5">
                        <path fillRule="evenodd" d="M3 10a.75.75 0 0 1 .75-.75h10.638L10.23 5.29a.75.75 0 1 1 1.04-1.08l5.5 5.25a.75.75 0 0 1 0 1.08l-5.5 5.25a.75.75 0 1 1-1.04-1.08l4.158-3.96H3.75A.75.75 0 0 1 3 10Z" clipRule="evenodd" />
                      </svg>

                    </button>
                    <button className="rounded-full bg-indigo-600/30 border border-indigo-500/50 px-6 py-3.5 text-base font-semibold text-white shadow-sm hover:bg-indigo-600/40 focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-indigo-500 transition border-1">
                      Find College
                    </button>
                      <button className="rounded-full bg-transparent border border-white/30 px-6 py-3.5 text-base font-semibold text-white shadow-sm hover:bg-white/10 transition">
                      Get Expert Counselling
                    </button>
              </div>


              {/* Bottom Trust Indicators */}
              <div className="mt-16 border-t border-white/10 pt-8 flex flex-wrap gap-8 md:gap-16">
                  <div>
                        <div className="text-2xl font-bold text-white">12,000+</div>
                        <div className="text-sm text-gray-400">Verified Reviews</div>
                  </div>
                    <div>
                        <div className="text-2xl font-bold text-white">3,200</div>
                        <div className="text-sm text-gray-400">Colleges</div>
                  </div>
                    <div>
                        <div className="text-2xl font-bold text-white">87%</div>
                        <div className="text-sm text-gray-400">Student Satisfaction</div>
                  </div>
              </div>

            </div>
          </div>
        </div>
      )}

      {(step === "profile" || step === "questions") && (
        <AnimatedPageWrapper>
          {step === "profile" && (
            <div className="py-12 w-full">
              <div className="max-w-4xl mx-auto px-4">
                  <ProfileForm onSubmit={handleProfileSubmit} setAlert={setAlert} />
              </div>
            </div>
          )}

          {step === "questions" && (
            <div className="py-12 w-full">
              <div className="max-w-4xl mx-auto px-4">
                    <Questionnaire
                      questions={questions}
                      onSubmit={handleAssessmentSubmit}
                    />
              </div>
            </div>
          )}
        </AnimatedPageWrapper>
      )}
    </div>
  );
}
